#ifdef __cplusplus
extern "C" {
#endif

#include <stdlib.h>
#include <stdio.h>
#include <math.h>
#include <omp.h>

#define fp float

#define NUMBER_PAR_PER_BOX 100

#define NUMBER_THREADS 128

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct
{
	fp x, y, z;
} THREE_VECTOR;

typedef struct
{
	fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
	int x, y, z;
	int number;
	long offset;
} nei_str;

typedef struct box_str
{
	int x, y, z;
	int number;
	long offset;
	int nn;
	nei_str nei[26];
} box_str;

typedef struct par_str
{
	fp alpha;
} par_str;

typedef struct dim_str
{
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;
	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;
} dim_str;

void kernel_gpu_opencl(par_str d_par_gpu,
					dim_str d_dim_gpu,
					box_str *d_box_gpu,
					FOUR_VECTOR *d_rv_gpu,
					fp *d_qv_gpu,
					FOUR_VECTOR *d_fv_gpu)
{
	#pragma omp parallel
	{
		FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
		FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
		fp qB_shared[NUMBER_PAR_PER_BOX];

		int bx = omp_get_thread_num();
		int tx = 0; 
		int wtx = tx;

		if(bx < d_dim_gpu.number_boxes){

			fp a2 = 2*d_par_gpu.alpha*d_par_gpu.alpha;
			int first_i;
			int pointer;
			int k = 0;
			int first_j;
			int j = 0;
			fp r2;
			fp u2;
			fp vij;
			fp fs;
			fp fxij;
			fp fyij;
			fp fzij;
			THREE_VECTOR d;

			first_i = d_box_gpu[bx].offset;

			for (wtx = tx; wtx < NUMBER_PAR_PER_BOX; wtx += NUMBER_THREADS) {
				rA_shared[wtx] = d_rv_gpu[first_i+wtx];
			}
			wtx = tx;

			for (k=0; k<(1+d_box_gpu[bx].nn); k++){

				if(k==0){
					pointer = bx;
				}
				else{
					pointer = d_box_gpu[bx].nei[k-1].number;
				}

				first_j = d_box_gpu[pointer].offset;

				for (wtx = tx; wtx < NUMBER_PAR_PER_BOX; wtx += NUMBER_THREADS) {
					rB_shared[wtx] = d_rv_gpu[first_j+wtx];
					qB_shared[wtx] = d_qv_gpu[first_j+wtx];
				}
				wtx = tx;

				for (wtx = tx; wtx < NUMBER_PAR_PER_BOX; wtx += NUMBER_THREADS) {
					for (j=0; j<NUMBER_PAR_PER_BOX; j++){
						r2 = rA_shared[wtx].v + rB_shared[j].v - DOT(rA_shared[wtx],rB_shared[j]); 
						u2 = a2*r2;
						vij= exp(-u2);
						fs = 2*vij;
						d.x = rA_shared[wtx].x  - rB_shared[j].x;
						fxij=fs*d.x;
						d.y = rA_shared[wtx].y  - rB_shared[j].y;
						fyij=fs*d.y;
						d.z = rA_shared[wtx].z  - rB_shared[j].z;
						fzij=fs*d.z;
						d_fv_gpu[first_i+wtx].v +=  qB_shared[j]*vij;
						d_fv_gpu[first_i+wtx].x +=  qB_shared[j]*fxij;
						d_fv_gpu[first_i+wtx].y +=  qB_shared[j]*fyij;
						d_fv_gpu[first_i+wtx].z +=  qB_shared[j]*fzij;
					}
				}
				wtx = tx;
			}
		}
	}
}

#ifdef __cplusplus
}
#endif
